module RefModule (
    input clk,
    input sreset,
    input enable,
    input [11:0] data,
    output [11:0] q );reg [11:0] q_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (sreset)
        q_reg <= 12'b000000000000;
    else if (enable)
        q_reg <= data;
end

assign q = q_reg;

endmodule
